# coding: utf-8
import json

import click
from tabulate import tabulate

from rainbow_admin.cli import err, info
from rainbow_admin.cli.group import get_group_by_id_or_name
from rainbow_admin.kv import KeyValue

CONFIG_HEADER = [
    "id",
    "key",
    "value",
    "description",
    "operator",
    "create_time",
    "status",
    "from_group_id",
]


def format_value(value):
    if not isinstance(value, str):
        value = str(value)
    more = False
    value = value.replace("\n", " ")
    if len(value) > 30:
        value = value[:27]
        more = True
    more = "..." if more else ""
    return f"{value}{more}"


def format_config(kv: KeyValue):
    return [
        kv.id,
        kv.key,
        format_value(kv.value),
        kv.description,
        kv.operator,
        kv.create_time,
        kv.status,
        kv.public_group.group_name if kv.is_public_config else "私有",
    ]


@click.group(name="config")
@click.option(
    "-g",
    "--group",
    help="id or name of group",
    show_envvar=True,
    envvar="RAINBOW_GROUP",
)
@click.pass_context
def config_cli(ctx, group):
    """actions about config"""
    group_instance = get_group_by_id_or_name(ctx.obj["admin"], group)
    if group_instance is None:
        return
    if not group_instance.is_kv:
        err(f"'{group}' 不是K-V型分组。请使用rainbow-admin table")
    ctx.obj["group"] = group_instance


@config_cli.command(help="list all config")
@click.option(
    "-f",
    "--format",
    default="table",
    help="result format",
    type=click.Choice(["table", "json", "raw"]),
)
@click.pass_context
def ls(ctx, format):
    group = ctx.obj["group"]
    kvs = group.configs

    data = [format_config(i) for i in kvs.values()]
    if format == "table":
        info(
            f"app_id={group.admin.app_id}, group_id={group.group_id}, group_name={group.group_name} configs:"
        )
        click.echo(tabulate(data, CONFIG_HEADER, tablefmt="pretty"))
    elif format == "json":
        click.echo(
            json.dumps(
                [i.to_dict() for i in kvs.values()], ensure_ascii=False, indent=4
            )
        )
    elif format == "raw":
        click.echo(json.dumps(group.get_info(), ensure_ascii=False, indent=4))


@config_cli.command(help="get config detail")
@click.argument("key", required=True)
@click.option(
    "-f",
    "--format",
    default="table",
    help="result format",
    type=click.Choice(["table", "json", "raw"]),
)
@click.pass_context
def get(ctx, key, format):
    group = ctx.obj["group"]
    kv: KeyValue = group.configs.get(key)
    if kv is None:
        err(f"未找到名为 {key} 的配置")
        return
    if format == "table":
        CONFIG_HEADER.remove("value")
        click.echo(
            tabulate([(k, getattr(kv, k)) for k in CONFIG_HEADER], tablefmt="plain")
        )
        split = "-" * 15
        click.echo(f"{split} value {split}")
        click.echo(kv.origin_value)
    elif format == "json":
        click.echo(json.dumps(kv.to_api_value()))


@config_cli.command(help="delete config detail")
@click.argument("key", required=True)
@click.pass_context
def delete(ctx, key):
    group = ctx.obj["group"]
    kv: KeyValue = group.configs.get(key)
    if kv is None:
        err(f"未找到名为 {key} 的配置")
        return
    kv.delete()
    info("删除成功")


@config_cli.command("set", help="set config")
@click.argument("key", required=True)
@click.argument("value", required=True)
@click.option(
    "-t",
    "--value-type",
    default="NONE",
    type=click.Choice(KeyValue.VALUE_TYPE_MAP.values(), False),
)
@click.option("-d", "--description", default="", help="description of group")
@click.pass_context
def set_config(ctx, key, value, value_type, description):
    group = ctx.obj["group"]
    kv: KeyValue = group.configs.get(key)
    value_type = [k for k, v in KeyValue.VALUE_TYPE_MAP.items() if v == value_type][0]
    new = False
    if kv is None:
        new = True
        kv = KeyValue(key, value, value_type, description, group=group)
    kv.value = value
    kv.save()
    if new:
        info(f"添加 {key} 成功")
    else:
        info(f"修改 {key} 成功")
